var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마. 아빠가 안 보여.","JPN":"ママ、パパがいないの。","ENG":"Mom, where's Dad?","TWN":"媽媽，爸爸不見了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"숲에도 가 보고 지하실에도 가 봤는데 아무데도 없어.","JPN":"森にも地下室にも行ってみたけど、どこにもいないの。","ENG":"I looked around the forest, and then in the basement, but I couldn't find him.","TWN":"我去樹林看過，也去地下室找過了，但都沒有找到。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"레지나, 아빠는 <color=#ffd34c>호수</color>를 찾으러 가셨단다.","JPN":"レジーナ、パパは<color=#ffd34c>湖</color>を探しに行ったのよ。","ENG":"Your father left to find the <color=#ffd34c>Lake</color>, Regina.","TWN":"蕾佳娜，爸爸去找<color=#ffd34c>湖</color>了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"호수? 왜? 호수는 우리 집에도 있는데?","JPN":"湖？　どうして？　湖はうちの森にもあるのに？","ENG":"Lake? Why? We have a lake near our house.","TWN":"湖？為什麼？湖我們家裡也有啊？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"아빠가 찾으러 간 호수는 그런 평범한 호수가 아니란다.","JPN":"パパが探しに行った湖は普通の湖ではないの。","ENG":"This Lake your father went looking for isn't an ordinary one.","TWN":"爸爸去找的湖不是那種普通的湖。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"우리 학회가 아주 오랫동안 찾아 헤매 온...... 지식의 호수지.","JPN":"学会がずっと昔から探し求めていた……知識の湖よ。","ENG":"It's something that the Society has been looking for very long time... The Lake of Knowledge.","TWN":"而是我們學會尋找很久很久的……知識之湖。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"정말? 그럼 나도 찾으러 갈래! 내가 찾으면 칭찬해 줄 거야?","JPN":"本当？　それなら私も探しに行く！　私が見つけたら褒めてくれる？","ENG":"Really? Then I want to go, too! Will you be happy if I find it?","TWN":"真的嗎？那我也要去找！如果我找到的話，媽媽會稱讚我嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"너무 서두를 필요 없단다. 우리 딸이 언젠가 엄마 뒤를 이어서 학회장이 되면......","JPN":"そんなに急がなくてもいいの。あなたがいつか、ママの後を継いで学会長になったら……","ENG":"You don't have to be so hasty, honey. When you take my post as the President of the Society in the future,","TWN":"不用太著急。只要我們的女兒能繼媽媽之後，當上學會長的話……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"함께 호수를 찾으러 가자꾸나.","JPN":"一緒に湖を探しに行きましょうね。","ENG":"we can go looking for the Lake together.","TWN":"我們就一起去找那座湖吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"......그 결과, 이면세계에 있는 유적지는 고고학에서 새로운 연구 분야로 각광 받게 된 겁니다.","JPN":"……その結果、裏世界にある遺跡は考古学における\\n新たな研究分野として脚光を浴びることになったのです。","ENG":"...And so, ruins in the Counterside came into the spotlight as the new research subject in archaeology.","TWN":"……結果，在異界的遺跡就成為考古學新研究的領域了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"시간이 그새 이렇게 됐군요. 오늘 강의는 여기서 마치기로 하죠.","JPN":"いつの間にかこんな時間ですね。今日の講義はここまでにしましょう。","ENG":"Oh, look at the time. Class is dismissed.","TWN":"我們不知不覺就到下課時間了，今天的課程就到這裡。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그리고 맥크레디 양은 잠깐 남아 주세요. 따로 할 얘기가 있습니다.","JPN":"それから、マクレディーさんは残ってください。お話がありますので。","ENG":"And Ms. MacCready, please come see me for a minute. I have something to tell you in person.","TWN":"然後請麥克蕾蒂小姐稍微留下來一下。我有一些話要說。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"무슨 일이시죠, 교수님?","JPN":"教授、お話というのは……？","ENG":"You wanted to see me, Professor?","TWN":"什麼事啊，教授？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"오다가 잠깐 학과 사무실에 들렀는데, 맥크레디 양 앞으로 편지가 와 있더군요.","JPN":"先ほど学科事務室に寄ったのですが、マクレディーさん宛てに手紙が届いていましてね。","ENG":"I stopped by the department office on the way. There was a letter addressed to you, Ms. MacCready.","TWN":"我來的時候去了一下學科辦公室，然後看到了一封給麥克蕾蒂小姐的信。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"아마 맥크레디 양을 스카우트하고 싶어하는 태스크포스 아닐까요?","JPN":"おそらく、マクレディーさんをスカウトしたがっているタスクフォースカンパニーではないでしょうか？","ENG":"I guess it's from a TASKFORCE company looking to hire you.","TWN":"大概是想要聘用麥克蕾蒂小姐的特遣勢力公司吧？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그쪽 업계로 간 졸업생들 얘기론 요새 어느 회사나 카운터가 없어서 야단이랍니다.","JPN":"あの業界へ進んだ卒業生たちの話によると、\\n最近はどこの会社もカウンターが少なくて困っているそうですから。","ENG":"The graduates that went to work in the business tells me there's a huge demand for Counters these days.","TWN":"聽去那邊工作的畢業生說，最近無論哪家公司都沒有制裁者。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 여기 봉랍에 찍힌 인장은......","JPN":"いいえ。この封蝋に刻まれた印章は……","ENG":"No, this seal on the envelope...","TWN":"不，這個封蠟上的印章是……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"맥크레디 양, 괜찮습니까? 안색이 나빠 보이는데요.","JPN":"マクレディーさん、大丈夫ですか？　顔色が悪いようですが。","ENG":"Is everything all right, Ms. MacCready? You don't look well.","TWN":"麥克蕾蒂小姐，妳還好嗎？妳臉色看起來很不好呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"죄송합니다, 교수님. 한동안 강의에 나오기 어렵겠어요.","JPN":"申し訳ございません、教授。しばらく講義には出られないかもしれません。","ENG":"I'm sorry, Professor. I won't be able to attend classes for a while.","TWN":"非常抱歉，教授。我應該會有一段時間沒辦法來上課。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"네? 논문 제출이 코앞인데 갑자기 무슨 말입니까?","JPN":"え？　論文の提出が目前なのに、突然どういうことですか？","ENG":"Sorry? The deadline for your thesis is right around the corner. What's the matter?","TWN":"咦？馬上就要提交論文了，怎麼說得這麼突然？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......이건 제 본가에서 온 편지예요.","JPN":"……これは、私の実家からの手紙なのです。","ENG":"This letter was sent from home.","TWN":"……這是我老家寄來的信。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"집안에 급한 일이 생겼다네요. 가서 수습하고 와야겠습니다.","JPN":"家族に何か問題が起きたそうで……私が行って収拾をつけなければなりません。","ENG":"It seems there's a family emergency. I'm afraid I'll have to go take care of it in person.","TWN":"家裡有些急事，我得去處理一下才行。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"으음...... 집안일이라면 말리기 어렵겠군요.","JPN":"そうですか……ご家庭の事情ならば仕方ありませんね。","ENG":"Ah... Then it wouldn't be appropriate for me to say anything more.","TWN":"嗯……既然是家裡的事，那我也很難說什麼了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그럼 차라리 졸업 논문을 본가에서 마무리 짓는 게 어떤가요?","JPN":"それならば、いっそ卒業論文をご実家で仕上げては？","ENG":"Then why don't you finish your thesis while you're at home?","TWN":"那不如在家裡完成畢業論文怎麼樣？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"잘 설명하면 다른 교수님들도 이해해 주실 겁니다.","JPN":"きちんと説明すれば、他の教授方も理解してくれるはずですよ。","ENG":"I'll explain to the other professors. I'm sure they will understand.","TWN":"只要好好解釋，其他教授應該也會理解的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"배려해 주셔서 감사하지만, 그리 오래 머물진 않을 거예요.","JPN":"お気遣いありがとうございます。でも、そう長居をするつもりはございませんので。","ENG":"Thank you for your consideration, but it won't be long.","TWN":"非常感謝您的關照，但我不會停留太久的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"빠른 시일 내로 돌아오겠습니다. 너무 걱정 마세요, 교수님.","JPN":"すぐに戻ってまいります。心配ご無用ですわ、教授。","ENG":"I'll be back in a few days. Don't worry, Professor.","TWN":"我會儘快回來的。請不用太擔心，教授。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>외선 편도 열차가 제 3 승강장으로 들어오고 있습니다.</color>","JPN":"<color=#ffd34c>間もなく、外回り片道列車が3番ホームに到着いたします。</color>","ENG":"<color=#ffd34c>The outbound one-way train is now approaching the platform on track 3.</color>","TWN":"<color=#ffd34c>外線單軌列車正駛入第三月臺。</color>"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>열차에 탑승하실 분들은 여권과 차표를 준비하시기 바랍니다.</color>","JPN":"<color=#ffd34c>ご乗車になる方は、パスポートとチケットをご用意ください。</color>","ENG":"<color=#ffd34c>Please have your passport and your ticket ready before getting on board.</color>","TWN":"<color=#ffd34c>請搭乘本班列車的乘客準備好護照和車票。</color>"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"레지나 맥크레디 님, 안나 맥크레디 부인의 부고를 전합니다.","JPN":"レジーナ・マクレディー様。アンナ・マクレディー夫人が逝去されたことをお伝えいたします。","ENG":"Ms. Regina MacCready, we regretfully inform you that Mrs. MacCready has passed away.","TWN":"蕾佳娜·麥克蕾蒂大人，向您傳達安娜·麥克蕾蒂夫人的訃告。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"부인께서는 따님께서 돌아오시어 당신의 뜻을 이어 주길 바란다고 유언하셨습니다.","JPN":"夫人はお嬢様が戻り、遺志を継ぐことを望むとの遺言を残されました。","ENG":"Her last words were that she wanted you to come back and carry on her legacy.","TWN":"夫人的遺言是，希望女兒能回來繼承她的遺志。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"부디 부인의 마지막 바람이 이루어지기를 바랍니다.","JPN":"どうか、夫人の最期の望みをお聞き届けください。","ENG":"We sincerely hope her last wish will come true.","TWN":"請務必完成夫人的遺願。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"에크하르트 초월지식 학회 신임 학회장 ─ <color=#ffd34c>에델 마이트너</color>","JPN":"エクハルト超越知識学会新任学会長――<color=#ffd34c>エデル・マイトナー</color>","ENG":"The newly appointed President of Eckhart's\xA0Society\xA0for\xA0Preternatural\xA0Research, <color=#ffd34c>Edel Meitner</color>","TWN":"埃克哈特超越知識學會新任會長——<color=#ffd34c>艾瑟兒·邁特納</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};